// src/pages/Categorias.jsx
import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [nuevaCategoria, setNuevaCategoria] = useState({
    id: "",
    nombre: "",
    descripcion: "",
  });
  const [editando, setEditando] = useState(false);

  const API_URL = "http://localhost:5000/api/categorias";

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get(API_URL);
      setCategorias(res.data);
    } catch (error) {
      console.error("Error al obtener categorías:", error);
    }
  };

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const handleChange = (e) => {
    setNuevaCategoria({ ...nuevaCategoria, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editando) {
        await axios.put(`${API_URL}/${nuevaCategoria.id}`, nuevaCategoria);
        setEditando(false);
      } else {
        await axios.post(API_URL, nuevaCategoria);
      }

      setNuevaCategoria({ id: "", nombre: "", descripcion: "" });
      obtenerCategorias();
    } catch (error) {
      console.error("Error al guardar categoría:", error);
    }
  };

  const editarCategoria = (categoria) => {
    setNuevaCategoria(categoria);
    setEditando(true);
  };

  const eliminarCategoria = async (id) => {
    try {
      await axios.delete(`${API_URL}/${id}`);
      obtenerCategorias();
    } catch (error) {
      console.error("Error al eliminar categoría:", error);
    }
  };

  return (
    <div className="container mt-5">
      <div className="card shadow-lg border-0 rounded-4 mb-5">
        <div className="card-header bg-success text-white text-center py-3">
          <h2 className="mb-0">{editando ? "Editar Categoría" : "Agregar Categoría"}</h2>
        </div>

        <div className="card-body">
          <form onSubmit={handleSubmit} className="row g-3">
            <div className="col-md-6">
              <label className="form-label">Nombre</label>
              <input
                type="text"
                name="nombre"
                value={nuevaCategoria.nombre}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-md-6">
              <label className="form-label">Descripción</label>
              <input
                type="text"
                name="descripcion"
                value={nuevaCategoria.descripcion}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-12 text-center mt-3">
              <button
                type="submit"
                className={`btn ${editando ? "btn-warning" : "btn-primary"} px-5`}
              >
                {editando ? "Actualizar" : "Agregar"}
              </button>
            </div>
          </form>
        </div>
      </div>

      <div className="card shadow-sm border-0 rounded-4">
        <div className="card-header bg-dark text-white text-center py-3">
          <h3 className="mb-0">Lista de Categorías</h3>
        </div>

        <div className="card-body">
          {categorias.length === 0 ? (
            <p className="text-center text-muted">No hay categorías registradas.</p>
          ) : (
            <div className="table-responsive">
              <table className="table table-striped table-hover align-middle text-center">
                <thead className="table-success">
                  <tr>
                    <th>ID</th>
                    <th>Nombre</th>
                    <th>Descripción</th>
                    <th>Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {categorias.map((c) => (
                    <tr key={c.id}>
                      <td>{c.id}</td>
                      <td>{c.nombre}</td>
                      <td>{c.descripcion}</td>
                      <td>
                        <button
                          className="btn btn-warning btn-sm me-2"
                          onClick={() => editarCategoria(c)}
                        >
                          Editar
                        </button>
                        <button
                          className="btn btn-danger btn-sm"
                          onClick={() => eliminarCategoria(c.id)}
                        >
                          Eliminar
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
